class Solution:
    def removeDuplicates(self, head: Node) -> Node:
        if not head or not head.next:
            return head

        current = head
        dummy = Node()
        dummy.next = head
        prev = dummy

        while current.next:
            if current.val == current.next.val:
                current = current.next
            else:
                prev.next = current
                prev = current
                current = current.next
        prev.next = current
        return dummy.next

