// C++ solution
#include <iostream>

using namespace std;

struct Node {
    int val;
    Node* next;
};

class Solution {
public:
    Node* removeDuplicates(Node* head) {
        if (head == nullptr || head->next == nullptr) return head;

        Node* current = head;
        Node* dummy = new Node();
        dummy->next = head;
        Node* prev = dummy;

        while (current->next) {
            if (current->val == current->next->val) {
                current = current->next;
            } else {
                prev->next = current;
                prev = current;
                current = current->next;
            }
        }
        prev->next = current;
        return dummy->next;
    }
};
